+fn use_wgpu_renderer() -> bool {
+    static CHOICE: OnceLock<bool> = OnceLock::new();
+    *CHOICE.get_or_init(|| {
+        match std::env::var("SB_RENDERER").ok().as_deref() {
+            Some("canvas") => false,
+            Some("wgpu") => true,
+            _ => true,
+        }
+    })
+}
